return {
-- Define the error message and category to be used if the module is used in -- the main namespace and the template config doesn't set the -- isUsedInMainspace key to true. The category is optional; if it is not -- wanted, set NAMESPACE_ERROR_CATEGORY to nil. namespaceError = 'Error: Please do not use this template in articles.', namespaceErrorCategory = 'Pages with templates in the wrong namespace',
-- The separator to be used if no separator is specified in the template -- config. defaultSeparator = mw.message.new('Dot-separator'):plain()
}

